import { hasPermissionCode } from '../utils/erpPermissionCode';

const PREFIX = 'erp-supply:purchasing:receiving-notes';

export function usePnhPermissions() {
  const canWrite = hasPermissionCode(`${PREFIX}:write`);
  return {
    canRead: hasPermissionCode(`${PREFIX}:read`),
    canWrite,
    canCreate: canWrite,
    canPost: hasPermissionCode(`${PREFIX}:post`) || canWrite,
  };
}
